const assert = require('node:assert')
const config = require('haraka-config')
const transaction = require('../transaction')

const _set_up = (done) => {
    this.transaction = transaction.createTransaction(undefined, config.get('smtp.ini'))
    done()
}

describe('add_header bug', () => {
    beforeEach(_set_up)

    // Test that add_header after end_data properly includes headers
    // in the piped output (not at the end of the body)
    it('add_header after end_data: appended headers appear before body in output', (done) => {
        this.transaction.add_data('From: test@example.com\r\n')
        this.transaction.add_data('To: rcpt@example.com\r\n')
        this.transaction.add_data('Subject: Test\r\n')
        this.transaction.add_data('\r\n') // header/body separator
        this.transaction.add_data('This is the body.\r\n')

        this.transaction.add_header('X-Appended-Header', 'appended_value')

        this.transaction.end_data(() => {
            // Now add another header after end_data
            this.transaction.add_header('X-Post-End-Data', 'post_end_value')

            this.transaction.message_stream.get_data((body) => {
                const output = body.toString()
                console.log('FULL OUTPUT:\n' + output)

                // Check that the appended header appears in the header section
                // (before the body), not after the body
                const xAppendedPos = output.indexOf('X-Appended-Header')
                const xPostEndPos = output.indexOf('X-Post-End-Data')
                const bodyPos = output.indexOf('This is the body.')

                assert.ok(xAppendedPos >= 0, 'X-Appended-Header should be in output')
                assert.ok(xPostEndPos >= 0, 'X-Post-End-Data should be in output')
                assert.ok(bodyPos >= 0, 'body should be in output')

                // Both headers should appear before the body
                assert.ok(xAppendedPos < bodyPos, 'X-Appended-Header should be before body')
                assert.ok(xPostEndPos < bodyPos, 'X-Post-End-Data should be before body')

                done()
            })
        })
    })

    // Test that add_header called before end_data still works
    it('add_header before end_data: header appears in output before body', (done) => {
        this.transaction.add_data('From: test@example.com\r\n')
        this.transaction.add_data('To: rcpt@example.com\r\n')
        this.transaction.add_data('Subject: Test\r\n')
        this.transaction.add_data('\r\n')
        this.transaction.add_data('This is the body.\r\n')

        this.transaction.add_header('X-Before-End', 'before_end_value')

        this.transaction.end_data(() => {
            this.transaction.message_stream.get_data((body) => {
                const output = body.toString()
                console.log('FULL OUTPUT (before end_data):\n' + output)

                const xHeaderPos = output.indexOf('X-Before-End')
                const bodyPos = output.indexOf('This is the body.')

                assert.ok(xHeaderPos >= 0, 'X-Before-End should be in output')
                assert.ok(bodyPos >= 0, 'body should be in output')
                assert.ok(xHeaderPos < bodyPos, 'X-Before-End should be before body')

                done()
            })
        })
    })

    // Test the order: append vs original headers
    it('appended headers appear after original headers but before body', (done) => {
        this.transaction.add_data('Subject: Original Subject\r\n')
        this.transaction.add_data('From: original@example.com\r\n')
        this.transaction.add_data('\r\n')
        this.transaction.add_data('Body content here.\r\n')

        this.transaction.add_header('X-Appended', 'appended_value')

        this.transaction.end_data(() => {
            this.transaction.message_stream.get_data((body) => {
                const output = body.toString()
                console.log('FULL OUTPUT (order test):\n' + output)

                const subjectPos = output.indexOf('Subject: Original Subject')
                const fromPos = output.indexOf('From: original@example.com')
                const xAppendedPos = output.indexOf('X-Appended')
                const bodyPos = output.indexOf('Body content here.')

                assert.ok(subjectPos >= 0, 'Subject should be in output')
                assert.ok(fromPos >= 0, 'From should be in output')
                assert.ok(xAppendedPos >= 0, 'X-Appended should be in output')
                assert.ok(bodyPos >= 0, 'body should be in output')

                // Appended header should be after original headers
                assert.ok(xAppendedPos > fromPos, 'X-Appended should come after original headers')
                // Appended header should be before body
                assert.ok(xAppendedPos < bodyPos, 'X-Appended should be before body')

                done()
            })
        })
    })

    // Test that multiple add_header calls work correctly
    it('multiple add_header calls produce correct output', (done) => {
        this.transaction.add_data('Subject: Multi-test\r\n')
        this.transaction.add_data('\r\n')
        this.transaction.add_data('Multi-test body.\r\n')

        this.transaction.add_header('X-First', 'first_value')
        this.transaction.add_header('X-Second', 'second_value')

        this.transaction.end_data(() => {
            this.transaction.add_header('X-Third', 'third_value')

            this.transaction.message_stream.get_data((body) => {
                const output = body.toString()
                console.log('FULL OUTPUT (multi):\n' + output)

                const bodyPos = output.indexOf('Multi-test body.')
