const assert = require('node:assert')
const stream = require('node:stream')
const config = require('haraka-config')
const transaction = require('../transaction')

const _set_up = (done) => {
    this.transaction = transaction.createTransaction(undefined, config.get('smtp.ini'))
    done()
}

describe('add_header bug - comprehensive tests', () => {
    beforeEach(_set_up)

    // Helper to collect pipe output
    function collect_pipe_output(ms, options, cb) {
        const buffers = []
        const ws = new stream.Writable({
            write(chunk, _enc, done) {
                buffers.push(Buffer.from(chunk))
                done()
            },
            final(done) {
                cb(Buffer.concat(buffers))
                done()
            }
        })
        ms.pipe(ws, options)
    }

    // Test 1: Basic add_header before end_data
    it('add_header before end_data: header appears in correct section', (done) => {
        const txn = transaction.createTransaction(undefined, config.get('smtp.ini'))
        txn.add_data('From: test@example.com\r\n')
        txn.add_data('Subject: Test\r\n')
        txn.add_data('\r\n') // EOH
        txn.add_data('Body text.\r\n')

        txn.add_header('X-Added', 'added_value')

        txn.end_data(() => {
            collect_pipe_output(txn.message_stream, {}, (data) => {
                const output = data.toString()
                console.log('Test 1 output:\n' + output)

                const xHeaderIdx = output.indexOf('X-Added')
                const subjectIdx = output.indexOf('Subject')
                const bodyIdx = output.indexOf('Body text.')
                const eohIdx = output.indexOf('\r\n\r\n')

                assert.ok(xHeaderIdx >= 0, 'X-Added header present')
                // X-Added should be after Subject and before the body
                assert.ok(xHeaderIdx > subjectIdx, 'X-Added after Subject')
                assert.ok(xHeaderIdx < bodyIdx, 'X-Added before body')
                done()
            })
        })
    })

    // Test 2: add_header after end_data (common for plugins in data_post)
    it('add_header after end_data: header appears in correct section', (done) => {
        const txn = transaction.createTransaction(undefined, config.get('smtp.ini'))
        txn.add_data('To: rcpt@example.com\r\n')
        txn.add_data('Subject: Test\r\n')
        txn.add_data('\r\n')
        txn.add_data('Body text here.\r\n')

        txn.end_data(() => {
            // This simulates what plugins do in data_post
            txn.add_header('X-Plugin-Added', 'plugin_value')

            collect_pipe_output(txn.message_stream, {}, (data) => {
                const output = data.toString()
                console.log('Test 2 output:\n' + output)

                const xHeaderIdx = output.indexOf('X-Plugin-Added')
                const bodyIdx = output.indexOf('Body text here.')

                assert.ok(xHeaderIdx >= 0, 'X-Plugin-Added header present')
                assert.ok(xHeaderIdx < bodyIdx, 'X-Plugin-Added before body')
                done()
            })
        })
    })

    // Test 3: Multiple add_header calls, some before and some after end_data
    it('add_header mixed before/after end_data works correctly', (done) => {
        const txn = transaction.createTransaction(undefined, config.get('smtp.ini'))
        txn.add_data('Subject: Mixed Test\r\n')
        txn.add_data('\r\n')
        txn.add_data('Mixed body.\r\n')

        txn.add_header('X-Before-End', 'before_value')

        txn.end_data(() => {
            txn.add_header('X-After-End', 'after_value')

            collect_pipe_output(txn.message_stream, {}, (data) => {
                const output = data.toString()
                console.log('Test 3 output:\n' + output)

                const beforeIdx = output.indexOf('X-Before-End')
                const afterIdx = output.indexOf('X-After-End')
                const bodyIdx = output.indexOf('Mixed body.')
                const subjectIdx = output.indexOf('Subject')

                assert.ok(beforeIdx >= 0, 'X-Before-End present')
                assert.ok(afterIdx >= 0, 'X-After-End present')
                // Both after Subject
                assert.ok(beforeIdx > subjectIdx, 'X-Before-End after Subject')
                assert.ok(afterIdx > subjectIdx, 'X-After-End after Subject')
                // Both before body
                assert.ok(beforeIdx < bodyIdx, 'X-Before-End before body')
                assert.ok(afterIdx < bodyIdx, 'X-After-End before body')
                // In correct order (before-end first, then after-end)
                assert.ok(beforeIdx < afterIdx, 'X-Before-End before X-After-End')
                done()
            })
        })
    })

    // Test 4: add_header with leading_header mixed
    it('add_header and add_leading_header in correct order', (done) => {
        const txn = transaction.createTransaction(undefined, config.get('smtp.ini'))
        txn.add_data('Subject: Order Test\r\n')
        txn.add_data('\r\n')
        txn.add_data('Order body.\r\n')

        txn.add_header('X-Appended', 'appended_value')
        txn.add_leading_header('X-Leading', 'leading_value')

        txn.end_data(() => {
            collect_pipe_output(txn.message_stream, {}, (data) => {
                const output = data.toString()
                console.log('Test 4 output:\n' + output)

                const leadingIdx = output.indexOf('X-Leading')
                const subjectIdx = output.indexOf('Subject')
                const appendedIdx = output.indexOf('X-Appended')
                const bodyIdx = output.indexOf('Order body.')

                assert.ok(leadingIdx >= 0, 'X-Leading present')
                assert.ok(appendedIdx >= 0, 'X-Appended present')
                // Leading before Subject
                assert.ok(leadingIdx < subjectIdx, 'X-Leading before Subject')
                // Append after Subject
                assert.ok(appendedIdx > subjectIdx, 'X-Appended after Subject')
                // All before body
                assert.ok(leadingIdx < bodyIdx, 'X-Leading before body')
                assert.ok(appendedIdx < bodyIdx, 'X-Appended before body')
                done()
            })
        })
    })

    // Test 5: Simulate add_header followed by remove_header then re-add
    // This simulates the auth_results_clean flow
    it('add_header, remove_header, re-add_header: final output correct', (done) => {
        const txn = transaction.createTransaction(undefined, config.get('smtp.ini'))
        txn.add_data('Subject: Auth Test\r\n')
        txn.add_data('Authentication-Results: original-result\r\n')
        txn.add_data('\r\n')
        txn.add_data('Auth body.\r\n')

        // Simulate auth_results_clean: move A-R to Original-A-R
        const ars = txn.header.get_all('Authentication-Results')
        for (const element of ars) {
            txn.add_header('Original-Authentication-Results', element)
        }
        txn.remove_header('Authentication-Results')

        // Simulate adding new A-R
        txn.add_header('Authentication-Results', 'new-result')

        txn.end_data(() => {
            collect_pipe_output(txn.message_stream, {}, (data) => {
                const output = data.toString()
                console.log('Test 5 output:\n' + output)

                const origArIdx = output.indexOf('Original-Authentication-Results')
                const arIdx = output.lastIndexOf('Authentication-Results')
                const bodyIdx = output.indexOf('Auth body.')

                assert.ok(origArIdx >= 0, 'Original-Authentication-Results present')
                assert.ok(arIdx >= 0, 'Authentication-Results present')
                // No duplicate (search for second occurrence)
                const firstAr = output.indexOf('Authentication-Results')
                const secondAr = output.indexOf('Authentication-Results', firstAr + 1)
                assert.ok(secondAr === -1, 'Only one Authentication-Results header')
                // Both before body
                assert.ok(origArIdx < bodyIdx, 'Original-Auth-Results before body')
                assert.ok(arIdx < bodyIdx, 'Auth-Results before body')

                done()
            })
        })
    })

    // Test 6: Verify that headers from add_header are NOT in the body section
    it('appended headers do not appear in body section', (done) => {
        const txn = transaction.createTransaction(undefined, config.get('smtp.ini'))
        txn.add_data('Subject: Body Test\r\n')
        txn.add_data('\r\n')
        txn.add_data('This is body content.\r\n')

        txn.add_header('X-Test', 'test_value')

        txn.end_data(() => {
            collect_pipe_output(txn.message_stream, {}, (data) => {
                const output = data.toString()
                console.log('Test 6 output:\n' + output)

                // Find EOH position
                const eohIdx = output.indexOf('\r\n\r\n')
                const bodyContent = output.substring(eohIdx + 4) // After the blank line

                // The body should NOT contain X-Test header
                assert.ok(!bodyContent.includes('X-Test'),
                    'X-Test header should NOT appear in body section')
                assert.ok(bodyContent.includes('This is body content.'),
                    'Body content should be in body section')
                done()
            })
        })
    })

    // Test 7: Empty email with only add_header
    it('add_header works with minimal email (just EOH)', (done) => {
        const txn = transaction.createTransaction(undefined, config.get('smtp.ini'))
        txn.add_data('\r\n') // EOH only
        txn.add_data('Minimal body.\r\n')

        // No original headers parsed
        txn.add_header('X-Only', 'only_value')

        txn.end_data(() => {
            collect_pipe_output(txn.message_stream, {}, (data) => {
                const output = data.toString()
                console.log('Test 7 output:\n' + output)

                const xOnlyIdx = output.indexOf('X-Only')
                const bodyIdx = output.indexOf('Minimal body.')

                assert.ok(xOnlyIdx >= 0, 'X-Only present')
                assert.ok(xOnlyIdx < bodyIdx, 'X-Only before body')
                done()
            })
        })
    })
})

